parameters.jsCode:
// Normalise every channel into one canonical schema + light validation.
const b = $json.body ?? $json;
const channel = (b.channel || 'web').toLowerCase();
const message = b.message || b.text || b.body || '';
if (!message || message.trim().length === 0) {
  throw new Error('VALIDATION: empty customer message');
}
// Stable correlation/audit id used across every node + log row.
const correlationId = b.correlationId || $execution.id + '-' + Date.now();
return {
  json: {
    correlationId,
    channel,
    message: message.trim(),
    customer: {
      id: b.customerId || b.contactId || null,
      email: b.email || null,
      name: b.name || null,
      company: b.company || null,
      companyDomain: b.companyDomain || (b.email ? b.email.split('@')[1] : null),
    },
    receivedAt: new Date().toISOString(),
    config: $('Set - Workflow Config').first().json,
  }
};

// Safely parse the LLM JSON; never let a malformed completion crash the run.
let parsed = { intent: 'general_inquiry', confidence: 0, reasoning: 'parse_fallback' };
try {
  const raw = ($json.output || '').replace(/```json|```/g, '').trim();
  parsed = JSON.parse(raw);
} catch (e) { parsed.reasoning = 'parse_error: ' + e.message; }
const ctx = $('Code - Normalize & Validate Payload').item.json;
return { json: { ...ctx, classification: parsed, intent: parsed.intent } };

let s = { sentiment:'neutral', sentimentScore:0, urgency:'medium', clvImpact:'low', churnProbability:0 };
try { s = JSON.parse(($json.output||'').replace(/```json|```/g,'').trim()); } catch(e) {}
const ctx = $('Code - Parse Classification').item.json;
return { json: { ...ctx, risk: s } };

// Consolidate every enrichment source by node name into one Customer 360 object.
const ctx = $('Code - Parse Sentiment & Risk').first().json;
const safe = (fn) => { try { return fn(); } catch(e) { return null; } };
const c360 = {
  hubspot:  safe(() => $('HubSpot - Get Contact').first().json),
  salesforce: safe(() => $('Salesforce - Get Account').first().json),
  airtable: safe(() => $('Airtable - Lookup Customer').first().json),
  history:  safe(() => $('Postgres - Customer History').first().json),
  billing:  safe(() => $('Stripe - Payment Records').all().map(i => i.json)),
};
return [{ json: { ...ctx, customer360: c360 } }];

// Transparent, explainable lead score (0-100) from enrichment + risk signals.
const j = $json; const c = j.customer360 || {};
let score = 40;
if (j.risk?.clvImpact === 'high') score += 25; else if (j.risk?.clvImpact === 'medium') score += 12;
if (c.billing && c.billing.length) score += 15;
if (j.risk?.urgency === 'high' || j.risk?.urgency === 'critical') score += 10;
if (j.customer?.company) score += 10;
score = Math.max(0, Math.min(100, score));
return { json: { ...j, leadScore: score, leadTier: score >= 75 ? 'A' : score >= 50 ? 'B' : 'C' } };

