// Flatten retrieved passages into a single context string (token-bounded).
const ctx = $('Code - Build Customer 360').first().json;
const passages = $input.all()
  .map(i => i.json.pageContent || i.json.text || JSON.stringify(i.json))
  .filter(Boolean).join('\n---\n').slice(0, 8000);
return [{ json: { ...ctx, ragContext: passages } }];

