let a = { answer:'', confidence:0, citedSources:0 };
try { a = JSON.parse(($json.output||'').replace(/```json|```/g,'').trim()); } catch(e) {}
const ctx = $('Code - Assemble RAG Context').first().json;
return { json: { ...ctx, aiAnswer: a } };

// Cancellation intent: assemble a retention play + flag high-value at-risk accounts.
const j = $json; const churn = j.risk?.churnProbability ?? 1;
const play = churn >= 0.6 ? 'executive_outreach+discount' : 'standard_winback';
return { json: { ...j, retention: { play, priority: j.risk?.clvImpact || 'low' } } };

const j = $json; const h = j.customer360?.history || {};
return { json: { ...j, features: {
  ticketCount: Number(h.ticket_count || 0),
  avgCsat: Number(h.avg_csat || 0),
  churnProbability: j.risk?.churnProbability ?? 0,
  sentimentScore: j.risk?.sentimentScore ?? 0,
  hasBilling: Boolean((j.customer360?.billing || []).length),
} } };

// Transparent predictive scores: churn risk, expansion, MRR projection.
const f = $json.features;
const churnRisk = Math.min(1, 0.6*f.churnProbability + 0.25*(f.avgCsat<3?1:0) + 0.15*(f.ticketCount>5?1:0));
const expansion = f.hasBilling && f.avgCsat >= 4 ? 'high' : f.hasBilling ? 'medium' : 'low';
const mrrProjection = f.hasBilling ? Math.round((1 - churnRisk) * 1000) : 0;
return { json: { ...$json, predictions: { churnRisk: Number(churnRisk.toFixed(3)), expansion, mrrProjection } } };
